import{c as r,Q as e,j as a,m as n}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"Agent Harness Engineering — 跨源知識地圖","description":"","frontmatter":{"title":"Agent Harness Engineering — 跨源知識地圖","type":"documentation"},"headers":[],"relativePath":"research/agent-harness/KNOWLEDGE-MAP.md","filePath":"research/agent-harness/KNOWLEDGE-MAP.md","lastUpdated":1779894392000}'),o={name:"research/agent-harness/KNOWLEDGE-MAP.md"};function s(i,t,d,l,h,g){return e(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="agent-harness-engineering-—-跨源知識地圖" tabindex="-1">Agent Harness Engineering — 跨源知識地圖 <a class="header-anchor" href="#agent-harness-engineering-—-跨源知識地圖" aria-label="Permalink to &quot;Agent Harness Engineering — 跨源知識地圖&quot;">​</a></h1><blockquote><p>建立時間：2026-05-01<br> 最後更新：2026-05-25（新增 8 篇 2026-05 論文 + 1 份 DebugML 報告）<br> 資料來源：11 份原始參考資料 + 17 份新 arXiv 論文 + 3 份新工程博客 + 1 份學術預警<br> 方法：跨源比對、共識萃取、分歧標注、缺口識別、實驗可信度驗證</p></blockquote><hr><h2 id="_1-知識地圖-主題覆蓋度" tabindex="-1">1. 知識地圖：主題覆蓋度 <a class="header-anchor" href="#_1-知識地圖-主題覆蓋度" aria-label="Permalink to &quot;1. 知識地圖：主題覆蓋度&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主題</th><th>來源數</th><th>代表來源</th><th>重要性</th></tr></thead><tbody><tr><td>Agent = Model + Harness（定義論）</td><td>6+</td><td>LangChain、HumanLayer、Osmani、Masood、RESEARCH.md</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td>Context Rot（性能衰退機制）</td><td>5+</td><td>Chroma、HumanLayer、Daily Dose DS、RESEARCH.md</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td>Sub-Agent 作為 Context Firewall</td><td>5+</td><td>HumanLayer、Trivedy、Daily Dose DS</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td>Ratchet 原則（失敗→永久規則）</td><td>5+</td><td>Hashimoto→HumanLayer→Osmani→FRAMEWORK.md</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td>Planner-Generator-Evaluator 三層</td><td>4+</td><td>Anthropic（Rajasekaran）、Daily Dose DS</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td>ReAct / Agentic Loop 基礎</td><td>4+</td><td>Weng、ReAct 論文、Willison、Trivedy</td><td>⭐⭐⭐⭐</td></tr><tr><td>Memory 架構（短期+長期+檢索）</td><td>4+</td><td>Weng、Memory Survey、Trivedy</td><td>⭐⭐⭐⭐</td></tr><tr><td>Tool Schema 設計原則</td><td>3+</td><td>Daily Dose DS、Tool Rewriting 論文、Yan</td><td>⭐⭐⭐⭐</td></tr><tr><td>Long-Horizon Execution（跨 session）</td><td>4+</td><td>Anthropic（Young）、Trivedy、Osmani</td><td>⭐⭐⭐⭐</td></tr><tr><td>Hooks（自動執行層）</td><td>3+</td><td>HumanLayer、Osmani、FRAMEWORK.md</td><td>⭐⭐⭐⭐</td></tr><tr><td>CLAUDE.md / AGENTS.md 作為配置槓桿</td><td>3+</td><td>HumanLayer、Osmani、FRAMEWORK.md</td><td>⭐⭐⭐⭐</td></tr><tr><td>MCP 與 Skills（能力擴展）</td><td>3+</td><td>HumanLayer、Trivedy、Masood</td><td>⭐⭐⭐</td></tr><tr><td>Scaffolding vs Harness 概念分離</td><td>2</td><td>Building Agents 論文、Daily Dose DS</td><td>⭐⭐⭐</td></tr><tr><td>5 個通用控制原語</td><td>2</td><td>Scaffold Taxonomy 論文、Weng</td><td>⭐⭐⭐</td></tr><tr><td>Harness 可移植性</td><td>1</td><td>NLAH 論文</td><td>⭐⭐</td></tr><tr><td>Harness 自動演進（Meta-Harness）</td><td>2</td><td>AHE 論文、Meta-Harness 論文</td><td>⭐⭐⭐</td></tr></tbody></table><hr><h2 id="_2-跨來源共識-consensus-points" tabindex="-1">2. 跨來源共識（Consensus Points） <a class="header-anchor" href="#_2-跨來源共識-consensus-points" aria-label="Permalink to &quot;2. 跨來源共識（Consensus Points）&quot;">​</a></h2><h3 id="共識-1-harness-優化效果等同於模型升級" tabindex="-1">共識 #1：Harness 優化效果等同於模型升級 <a class="header-anchor" href="#共識-1-harness-優化效果等同於模型升級" aria-label="Permalink to &quot;共識 #1：Harness 優化效果等同於模型升級&quot;">​</a></h3><p><strong>量化數據</strong>:</p><ul><li>Terminal-Bench：同 Opus 4.6，不同 harness → 13 pp 差距（66.9% vs 79.8%）</li><li>Stanford Meta-Harness：59.6% → 76.4%（16.8 pp）</li><li>實地案例（Ewan Mak）：58% → 81%（23 pp）</li><li>AHE 論文：69.7% → 77.0%（7.3 pp，10 次自動迭代）</li></ul><p><strong>各來源的表述</strong>:</p><ul><li>Osmani：「decent model + great harness beats great model + bad harness」</li><li>Masood：「企業 AI 失敗的 65% 源自 harness 層缺陷，而非模型」</li><li>Daily Dose DS：「LangChain 只改 harness，從外賽區升至第 5 名」</li></ul><p><strong>實踐結論</strong>: 在當前投資報酬率下，優化 harness &gt; 等待新模型版本。</p><hr><h3 id="共識-2-context-rot-不能靠更大的-context-window-解決" tabindex="-1">共識 #2：Context Rot 不能靠更大的 Context Window 解決 <a class="header-anchor" href="#共識-2-context-rot-不能靠更大的-context-window-解決" aria-label="Permalink to &quot;共識 #2：Context Rot 不能靠更大的 Context Window 解決&quot;">​</a></h3><p><strong>量化依據</strong>:</p><ul><li>Chroma NIAH 研究：18 個模型全部隨 context 長度下降；簡單任務在 2,500+ token 後崩潰</li><li>邏輯連貫的 haystack 反而表現更差（18 模型一致）</li></ul><p><strong>各來源的共識</strong>:</p><ul><li>HumanLayer + RESEARCH.md：Sub-agent 是唯一結構性解決方案</li><li>Daily Dose DS：Context Management 作為獨立 harness 組件（壓縮/masking/即時檢索）</li><li>Weng 論文：工作記憶（context）+ 長期存儲的混合是必需架構</li></ul><p><strong>實踐結論</strong>: 1M context window 是虛假安全感；結構性切割（sub-agent）才是解法。</p><hr><h3 id="共識-3-generator-永遠不能自評-三層分離是強制要求" tabindex="-1">共識 #3：Generator 永遠不能自評；三層分離是強制要求 <a class="header-anchor" href="#共識-3-generator-永遠不能自評-三層分離是強制要求" aria-label="Permalink to &quot;共識 #3：Generator 永遠不能自評；三層分離是強制要求&quot;">​</a></h3><p><strong>量化依據</strong>:</p><ul><li>Rajasekaran 案例：三層 harness vs 單層，同一模型性能差 6 小時 $200 vs 20 分鐘 $9</li><li>Daily Dose DS：Verification 能使品質提升 2-3 倍</li></ul><p><strong>各來源的共識</strong>:</p><ul><li>Anthropic（Rajasekaran）：Generator「自信地稱讚自己的工作，即使品質平庸」</li><li>Anthropic（Young）：Initializer + Coding Agent + Evaluator 三層</li><li>Eugene Yan：Evals pattern 是生產系統的基石</li></ul><p><strong>實踐結論</strong>: 長任務不能使用單層架構；評估者必須與生成者分離。</p><hr><h3 id="共識-4-每行-claude-md-agents-md-都應追蹤到具體失敗" tabindex="-1">共識 #4：每行 CLAUDE.md / AGENTS.md 都應追蹤到具體失敗 <a class="header-anchor" href="#共識-4-每行-claude-md-agents-md-都應追蹤到具體失敗" aria-label="Permalink to &quot;共識 #4：每行 CLAUDE.md / AGENTS.md 都應追蹤到具體失敗&quot;">​</a></h3><p><strong>各來源的共識</strong>:</p><ul><li>Hashimoto → HumanLayer → Osmani：Ratchet 原則的完整傳遞</li><li>FRAMEWORK.md：本 workspace 的規則淵源追蹤實踐</li><li>April 23 Postmortem：三個 harness 改動各自造成 3-13 pp 品質下降</li></ul><p><strong>實踐結論</strong>: Harness 是「從失敗中沉澱的規則集合」，不是「預先設計的架構」。</p><hr><h3 id="共識-5-tools-設計品質直接影響-agent-成功率" tabindex="-1">共識 #5：Tools 設計品質直接影響 Agent 成功率 <a class="header-anchor" href="#共識-5-tools-設計品質直接影響-agent-成功率" aria-label="Permalink to &quot;共識 #5：Tools 設計品質直接影響 Agent 成功率&quot;">​</a></h3><p><strong>量化依據</strong>:</p><ul><li>Tool Rewriting 論文（2602.20426）：措辭改變可顯著提升 agent 成功率</li><li>Daily Dose DS：工具 schema 是 LLM ↔ Tool 之間的形式合約</li></ul><p><strong>各來源的共識</strong>:</p><ul><li>Weng：工具是超越訓練數據的能力擴展管道</li><li>Masood：Tool/Function Calling 是 5 層 Control Plane 的第 2 層</li><li>Trivedy：工具描述消耗 context，需控制數量與質量</li></ul><p><strong>實踐結論</strong>: 工具設計不只是功能問題，也是 schema 語言和描述精確度的工程問題。</p><hr><h3 id="共識-6-harness-結構對性能的影響超過模型大小-結構性優勢" tabindex="-1">共識 #6：Harness 結構對性能的影響超過模型大小（結構性優勢） <a class="header-anchor" href="#共識-6-harness-結構對性能的影響超過模型大小-結構性優勢" aria-label="Permalink to &quot;共識 #6：Harness 結構對性能的影響超過模型大小（結構性優勢）&quot;">​</a></h3><p><strong>量化依據</strong> (2026-05 新數據):</p><ul><li>Vesper 論文（2605.15221）：算法發現任務上，harness 結構變異佔 40% 性能差距；模型大小只佔 30%</li><li>Adapting Interface, Not Model（2605.22166）：95% 的模型適應效果可在 harness 層實現，成本 2%</li></ul><p><strong>各來源的共識</strong>:</p><ul><li>Runtime Substrate（2605.13357）：五層 harness 架構分離模型(Invocation) 與上下文(Context/Memory/Coordination/Reflection)</li><li>Code as Agent Harness（2605.18747）：代碼結構本身（函簽、型別、文件字串）就是 harness；工具綱目可從 AST 自動編譯</li></ul><p><strong>實踐結論</strong>: Harness 是一級制約因子，不是模型的工具。結構最佳化報酬率 &gt; 等待模型升級。</p><hr><h3 id="共識-7-harness-可在運行時自學習演化-不需重訓練" tabindex="-1">共識 #7：Harness 可在運行時自學習演化（不需重訓練） <a class="header-anchor" href="#共識-7-harness-可在運行時自學習演化-不需重訓練" aria-label="Permalink to &quot;共識 #7：Harness 可在運行時自學習演化（不需重訓練）&quot;">​</a></h3><p><strong>量化依據</strong> (2026-05 新數據):</p><ul><li>Continual Harness（2605.09998）：運行時在線 RL 循環，無需模型重訓練即可自修改</li><li>Meta-Harness（2603.28052, Stanford/Chelsea Finn）：聯合優化 harness + 模型的收益 15-22%，harness 作為可學習參數</li></ul><p><strong>各來源的共識</strong>:</p><ul><li>AHE 論文：10 次自動迭代即可從 69.7% → 77.0%（7.3 pp），無需人工介入</li></ul><p><strong>實踐結論</strong>: Harness 演化是持續過程；應設計為「可參數化 + 可測試」而非「靜態規則」。</p><hr><h2 id="_3-分歧觀點-diverging-perspectives" tabindex="-1">3. 分歧觀點（Diverging Perspectives） <a class="header-anchor" href="#_3-分歧觀點-diverging-perspectives" aria-label="Permalink to &quot;3. 分歧觀點（Diverging Perspectives）&quot;">​</a></h2><h3 id="分歧-1-mcp-的投資報酬率" tabindex="-1">分歧 #1：MCP 的投資報酬率 <a class="header-anchor" href="#分歧-1-mcp-的投資報酬率" aria-label="Permalink to &quot;分歧 #1：MCP 的投資報酬率&quot;">​</a></h3><table tabindex="0"><thead><tr><th>立場</th><th>來源</th><th>論點</th></tr></thead><tbody><tr><td>保守</td><td>Simon Willison</td><td>不建議依賴 MCP；直接用 shell 命令更簡單和安全</td></tr><tr><td>積極</td><td>HumanLayer、Masood</td><td>MCP 是能力擴展主要途徑，採用 A2A 協議標準化</td></tr><tr><td>務實</td><td>FRAMEWORK.md</td><td>Bash + Read/Write + Glob 已覆蓋 90% 需求；MCP 有價值但不緊急</td></tr></tbody></table><p><strong>核心差異</strong>: Willison 優先安全隔離（Docker/Codespaces）；Masood 優先 context 效率與標準化。</p><hr><h3 id="分歧-2-model-進步後-harness-的演變方向" tabindex="-1">分歧 #2：Model 進步後 Harness 的演變方向 <a class="header-anchor" href="#分歧-2-model-進步後-harness-的演變方向" aria-label="Permalink to &quot;分歧 #2：Model 進步後 Harness 的演變方向&quot;">​</a></h3><table tabindex="0"><thead><tr><th>觀點</th><th>來源</th><th>預測</th></tr></thead><tbody><tr><td>Convergence（模型內化 harness 功能）</td><td>Trivedy</td><td>某些 harness 功能會成為模型原生能力</td></tr><tr><td>Substitution（簡單 harness 退場）</td><td>Anthropic Rajasekaran</td><td>V1 需要 sprint contracts，Opus 4.6 後不需要了</td></tr><tr><td>Permanence（校準型 harness 永遠留著）</td><td>RESEARCH.md</td><td>Harness 解的是 non-determinism，不是 model 弱點</td></tr></tbody></table><p><strong>深層分析</strong>:</p><ul><li>補弱點的 harness（early-stop、subagent for isolation）→ 隨模型進步消失</li><li>校準 non-determinism 的 harness（hooks、verification、planner-evaluator）→ 永遠留著</li></ul><hr><h3 id="分歧-3-verification-的自動化程度" tabindex="-1">分歧 #3：Verification 的自動化程度 <a class="header-anchor" href="#分歧-3-verification-的自動化程度" aria-label="Permalink to &quot;分歧 #3：Verification 的自動化程度&quot;">​</a></h3><table tabindex="0"><thead><tr><th>立場</th><th>來源</th><th>方法</th></tr></thead><tbody><tr><td>深度自動化</td><td>Anthropic Rajasekaran</td><td>Playwright UI 自動測試，live interaction before scoring</td></tr><tr><td>模型內評估</td><td>Anthropic Young</td><td>Unit tests + browser automation</td></tr><tr><td>輕量快速</td><td>HumanLayer</td><td>Typecheck + lint + unit tests，只顯示 errors</td></tr><tr><td>多層驗證</td><td>Daily Dose DS</td><td>規則型/視覺型/LLM-as-judge 三種層次</td></tr></tbody></table><hr><h3 id="分歧-4-harness-厚度-thick-vs-thin" tabindex="-1">分歧 #4：Harness 厚度（Thick vs Thin） <a class="header-anchor" href="#分歧-4-harness-厚度-thick-vs-thin" aria-label="Permalink to &quot;分歧 #4：Harness 厚度（Thick vs Thin）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>立場</th><th>來源</th><th>立場</th></tr></thead><tbody><tr><td>Thick（重型 harness）</td><td>Daily Dose DS、Masood</td><td>11 組件完整架構；Control Plane 5 層</td></tr><tr><td>Thin + 迭代（漸進式）</td><td>Building Agents 論文</td><td>從最簡 harness 開始，失敗後 Ratchet 增厚</td></tr><tr><td>隨模型簡化（Scaffolding 觀）</td><td>Daily Dose DS</td><td>好的 harness 是臨時基礎設施，隨模型進步應下降</td></tr></tbody></table><hr><h2 id="_4-formal-methods-architecture-taxonomy-2026-05-新增主題" tabindex="-1">4. Formal Methods &amp; Architecture Taxonomy（2026-05 新增主題） <a class="header-anchor" href="#_4-formal-methods-architecture-taxonomy-2026-05-新增主題" aria-label="Permalink to &quot;4. Formal Methods &amp; Architecture Taxonomy（2026-05 新增主題）&quot;">​</a></h2><h3 id="harness-作為範疇論架構-category-theory-foundation" tabindex="-1">Harness 作為範疇論架構（Category Theory Foundation） <a class="header-anchor" href="#harness-作為範疇論架構-category-theory-foundation" aria-label="Permalink to &quot;Harness 作為範疇論架構（Category Theory Foundation）&quot;">​</a></h3><p><strong>來源</strong>: Harness as Categorical Architecture（2605.12239）</p><p><strong>核心洞見</strong>:</p><ul><li>工具 = 物件（Objects）</li><li>管道 = 態射（Morphisms）</li><li>組合 = 函子律（Functorial Composition）</li><li>形式驗證：harness chain 的正確性可通過範疇圖進行證明</li></ul><p><strong>實踐意義</strong>:</p><ul><li>可形式化表示 harness 的組合規則</li><li>自動檢測「不可組合」的 pipeline 配置</li><li>為工具鏈提供數學保證而非經驗驗證</li></ul><hr><h3 id="五層-runtime-substrate-分離關切-separation-of-concerns" tabindex="-1">五層 Runtime Substrate 分離關切（Separation of Concerns） <a class="header-anchor" href="#五層-runtime-substrate-分離關切-separation-of-concerns" aria-label="Permalink to &quot;五層 Runtime Substrate 分離關切（Separation of Concerns）&quot;">​</a></h3><p><strong>來源</strong>: Runtime Substrate（2605.13357）</p><p><strong>架構分層</strong>:</p><table tabindex="0"><thead><tr><th>層級</th><th>責任</th><th>範例</th></tr></thead><tbody><tr><td><strong>Invocation Layer</strong></td><td>Model ↔ Tool 介面</td><td>Function call parsing、retry logic</td></tr><tr><td><strong>Context Layer</strong></td><td>上下文可見性管理</td><td>Compaction、windowing、injection</td></tr><tr><td><strong>Memory Layer</strong></td><td>短期/長期狀態</td><td>Session cache、vector DB、prompt cache</td></tr><tr><td><strong>Coordination Layer</strong></td><td>工具編排與順序</td><td>Pipeline routing、parallel execution、fork-join</td></tr><tr><td><strong>Reflection Layer</strong></td><td>自我監視與調適</td><td>Error detection、performance metrics、rule learning</td></tr></tbody></table><p><strong>實踐結論</strong>:</p><ul><li>清晰分層減少紐合，提高可測試性</li><li>各層獨立優化不破壞他層</li><li>顯式責任邊界便於診斷問題源頭</li></ul><hr><h2 id="_5-知識缺口-knowledge-gaps" tabindex="-1">5. 知識缺口（Knowledge Gaps） <a class="header-anchor" href="#_5-知識缺口-knowledge-gaps" aria-label="Permalink to &quot;5. 知識缺口（Knowledge Gaps）&quot;">​</a></h2><h3 id="缺口-1-harness-的量化評估框架-優先級-p0" tabindex="-1">缺口 #1：Harness 的量化評估框架（優先級 P0） <a class="header-anchor" href="#缺口-1-harness-的量化評估框架-優先級-p0" aria-label="Permalink to &quot;缺口 #1：Harness 的量化評估框架（優先級 P0）&quot;">​</a></h3><p><strong>現狀</strong>: Terminal-Bench 提供模型級基準，但無法診斷「特定 harness 的健康度」。<br><strong>影響</strong>: 無法量化本 workspace harness 的水準與優化方向。<br><strong>建議</strong>:</p><ul><li>harness-eval skill 對照 AHE 的三大可觀測性柱子</li><li>量化「context firewall 效率」（sub-agent 的中間輸出 vs 最終結論 token 比）</li><li>量化「Ratchet 累積度」（規則數量與覆蓋的失敗模式）</li></ul><hr><h3 id="缺口-2-rule-escalation-決策樹-優先級-p0" tabindex="-1">缺口 #2：Rule Escalation 決策樹（優先級 P0） <a class="header-anchor" href="#缺口-2-rule-escalation-決策樹-優先級-p0" aria-label="Permalink to &quot;缺口 #2：Rule Escalation 決策樹（優先級 P0）&quot;">​</a></h3><p><strong>現狀</strong>: 「每個失敗要變成規則」的哲學清楚，但「何時升格為 hook vs 留在 CLAUDE.md」無明確指引。<br><strong>案例</strong>:</p><ul><li>Commit 前 deep-review → 已升格為 hook（正確）</li><li>Context 70% compact 規則 → 留在 rules（應升格為自動 hook 嗎？）</li><li>No-commit 紅線 → security-hygiene.md（應升格為 git hook 嗎？）</li></ul><p><strong>建議</strong>: 建立決策樹：人工遵守率 × 違反成本 → 決定是否升格為 code 層 hook。</p><hr><h3 id="缺口-3-sub-agent-委派的精確閾值驗證-優先級-p1" tabindex="-1">缺口 #3：Sub-Agent 委派的精確閾值驗證（優先級 P1） <a class="header-anchor" href="#缺口-3-sub-agent-委派的精確閾值驗證-優先級-p1" aria-label="Permalink to &quot;缺口 #3：Sub-Agent 委派的精確閾值驗證（優先級 P1）&quot;">​</a></h3><p><strong>現狀</strong>: 「≥10 檔案」「&gt;20 工具呼叫」是啟發式規則，無量化驗證。<br><strong>問題</strong>:</p><ul><li>Sub-agent 的「收支平衡點」（開銷 token vs 救回的 context rot token）尚未測量</li><li>遞歸委派（main → sub1 → sub2）的邊際效益未知</li><li>Chroma 研究未測試多層 sub-agent 的遞歸效果</li></ul><hr><h3 id="缺口-4-long-horizon-的自動化進度追蹤-優先級-p1" tabindex="-1">缺口 #4：Long-Horizon 的自動化進度追蹤（優先級 P1） <a class="header-anchor" href="#缺口-4-long-horizon-的自動化進度追蹤-優先級-p1" aria-label="Permalink to &quot;缺口 #4：Long-Horizon 的自動化進度追蹤（優先級 P1）&quot;">​</a></h3><p><strong>現狀</strong>:</p><ul><li>Anthropic 推薦 Initializer + Progress + Git 架構</li><li>本 workspace 靠 Tasks.md 手動追蹤，缺乏自動化</li></ul><p><strong>建議</strong>:</p><ul><li>規範化 Progress 格式（JSON schema for <code>claude-progress.txt</code>）</li><li>自動偵測「premature completion」的 hook</li><li>Session 間自動驗證「新工作與舊工作無衝突」</li></ul><hr><h3 id="缺口-5-model-版本升級時-harness-的遷移指南-優先級-p2" tabindex="-1">缺口 #5：Model 版本升級時 Harness 的遷移指南（優先級 P2） <a class="header-anchor" href="#缺口-5-model-版本升級時-harness-的遷移指南-優先級-p2" aria-label="Permalink to &quot;缺口 #5：Model 版本升級時 Harness 的遷移指南（優先級 P2）&quot;">​</a></h3><p><strong>現狀</strong>: April 23 Postmortem 顯示 harness 改動造成整體性下滑，但無升級新模型時的 harness 微調指南。<br><strong>案例</strong>:</p><ul><li>Opus 4.7 預設 <code>xhigh</code>，Sonnet 4.6 預設 <code>high</code> — 何時切換？</li><li>Opus 4.7 自適應思考 — 是否要調整 hooks？</li><li>Forked subagent（v2.1.117）— 對 harness 設計的影響？</li></ul><hr><h3 id="缺口-6-cross-model-harness-可遷移性-優先級-p3" tabindex="-1">缺口 #6：Cross-Model Harness 可遷移性（優先級 P3） <a class="header-anchor" href="#缺口-6-cross-model-harness-可遷移性-優先級-p3" aria-label="Permalink to &quot;缺口 #6：Cross-Model Harness 可遷移性（優先級 P3）&quot;">​</a></h3><p><strong>現狀</strong>: 所有分析基於 Claude，無「harness 規則能否跨模型（GPT/Gemini）遷移」的研究。<br><strong>Terminal-Bench 洞見</strong>: GPT 和 Claude 表現接近，但依賴的 harness 不同，難以判斷是模型還是 harness 的優勢。</p><hr><h3 id="缺口-7-基準評測污染與可信度危機-優先級-p0-—-2026-05-新增" tabindex="-1">缺口 #7：基準評測污染與可信度危機（優先級 P0 — 2026-05 新增） <a class="header-anchor" href="#缺口-7-基準評測污染與可信度危機-優先級-p0-—-2026-05-新增" aria-label="Permalink to &quot;缺口 #7：基準評測污染與可信度危機（優先級 P0 — 2026-05 新增）&quot;">​</a></h3><p><strong>現狀（2026-05-23 重大發現）</strong>:</p><ul><li>DebugML「Cheating Agents」論文：業界排名前 20 的 agent 系統中 67% 顯示基準污染信號</li><li>污染類型：訓練集洩露、基準過擬合、評測集污染、結果後選擇性報告</li></ul><p><strong>影響</strong>:</p><ul><li>BENCHMARK.md 中引用的 Terminal-Bench、Vesper 等成績可能虛高 15-30 pp</li><li>「harness 結構佔 40% 方差」的實驗結論需獨立驗證</li><li>目前缺乏污染抵抗的開放基準</li></ul><p><strong>建議</strong>:</p><ul><li>對本 workspace 評測添加污染抵抗控制（out-of-distribution 保留集）</li><li>重新實驗 Vesper 等高影響力論文結論（獨立實現）</li><li>採用持續更新的基準而非靜態數據集</li></ul><hr><h2 id="_5-最重要的技術洞見-top-10" tabindex="-1">5. 最重要的技術洞見 Top 10 <a class="header-anchor" href="#_5-最重要的技術洞見-top-10" aria-label="Permalink to &quot;5. 最重要的技術洞見 Top 10&quot;">​</a></h2><h3 id="_1-harness-優化能交付-15-25-pp-性能提升-量級等同模型升級" tabindex="-1">#1：Harness 優化能交付 15-25 pp 性能提升，量級等同模型升級 <a class="header-anchor" href="#_1-harness-優化能交付-15-25-pp-性能提升-量級等同模型升級" aria-label="Permalink to &quot;#1：Harness 優化能交付 15-25 pp 性能提升，量級等同模型升級&quot;">​</a></h3><ul><li>來源：Terminal-Bench + AHE 論文 + RESEARCH.md</li><li><strong>行動意義</strong>: 優化 harness 是「主動控制」，等模型是「被動等待」；優先順序應最高</li></ul><h3 id="_2-context-rot-是系統性問題-唯一出路是結構性切割-sub-agent" tabindex="-1">#2：Context Rot 是系統性問題；唯一出路是結構性切割（Sub-Agent） <a class="header-anchor" href="#_2-context-rot-是系統性問題-唯一出路是結構性切割-sub-agent" aria-label="Permalink to &quot;#2：Context Rot 是系統性問題；唯一出路是結構性切割（Sub-Agent）&quot;">​</a></h3><ul><li>來源：Chroma NIAH + HumanLayer + RESEARCH.md</li><li><strong>行動意義</strong>: 任何超過 2,500 token 的中間產出都應考慮委派給 sub-agent</li></ul><h3 id="_3-sub-agent-不只是「換個人做」-本質是-context-firewall" tabindex="-1">#3：Sub-Agent 不只是「換個人做」，本質是 Context Firewall <a class="header-anchor" href="#_3-sub-agent-不只是「換個人做」-本質是-context-firewall" aria-label="Permalink to &quot;#3：Sub-Agent 不只是「換個人做」，本質是 Context Firewall&quot;">​</a></h3><ul><li>來源：HumanLayer + RESEARCH.md</li><li><strong>行動意義</strong>: 評估 sub-agent 時看「隔離了多少中間噪聲」，不只看結論品質</li></ul><h3 id="_4-generator-永遠無法自評-三層架構是強制要求而非可選優化" tabindex="-1">#4：Generator 永遠無法自評；三層架構是強制要求而非可選優化 <a class="header-anchor" href="#_4-generator-永遠無法自評-三層架構是強制要求而非可選優化" aria-label="Permalink to &quot;#4：Generator 永遠無法自評；三層架構是強制要求而非可選優化&quot;">​</a></h3><ul><li>來源：Anthropic Rajasekaran + Daily Dose DS</li><li><strong>行動意義</strong>: 任何長於 5 步的任務必須有獨立的 Evaluator</li></ul><h3 id="_5-ratchet-原則-每個失敗都沉澱成永久規則" tabindex="-1">#5：Ratchet 原則：每個失敗都沉澱成永久規則 <a class="header-anchor" href="#_5-ratchet-原則-每個失敗都沉澱成永久規則" aria-label="Permalink to &quot;#5：Ratchet 原則：每個失敗都沉澱成永久規則&quot;">​</a></h3><ul><li>來源：Hashimoto → HumanLayer → Osmani → FRAMEWORK.md（貫穿所有文獻）</li><li><strong>行動意義</strong>: Known Gotchas 是 Skill 中最有價值的 section；應持續維護</li></ul><h3 id="_6-april-23-postmortem-harness-改一行可以讓整個系統分布跑掉" tabindex="-1">#6：April 23 Postmortem：Harness 改一行可以讓整個系統分布跑掉 <a class="header-anchor" href="#_6-april-23-postmortem-harness-改一行可以讓整個系統分布跑掉" aria-label="Permalink to &quot;#6：April 23 Postmortem：Harness 改一行可以讓整個系統分布跑掉&quot;">​</a></h3><ul><li>來源：Anthropic April 23 Postmortem</li><li><strong>行動意義</strong>: Harness 改動需要廣泛測試 + 漸進推出 + 快速回滾機制</li></ul><h3 id="_7-long-horizon-需要三件套-initializer-規劃-progress-檔案-git-版本控制" tabindex="-1">#7：Long-Horizon 需要三件套：Initializer（規劃）+ Progress 檔案 + Git（版本控制） <a class="header-anchor" href="#_7-long-horizon-需要三件套-initializer-規劃-progress-檔案-git-版本控制" aria-label="Permalink to &quot;#7：Long-Horizon 需要三件套：Initializer（規劃）+ Progress 檔案 + Git（版本控制）&quot;">​</a></h3><ul><li>來源：Anthropic Young + RESEARCH.md</li><li><strong>行動意義</strong>: 跨 session 任務需要結構化狀態管理；手動 Tasks.md 只是暫時方案</li></ul><h3 id="_8-context-efficiency-核心-工具輸出應被-sub-agent「吃掉」-只有結論回流" tabindex="-1">#8：Context Efficiency 核心：工具輸出應被 Sub-Agent「吃掉」，只有結論回流 <a class="header-anchor" href="#_8-context-efficiency-核心-工具輸出應被-sub-agent「吃掉」-只有結論回流" aria-label="Permalink to &quot;#8：Context Efficiency 核心：工具輸出應被 Sub-Agent「吃掉」，只有結論回流&quot;">​</a></h3><ul><li>來源：HumanLayer + RESEARCH.md + Sub-agent delegation</li><li><strong>行動意義</strong>: 主 agent 看到的應該是 structured conclusions，不是 grep 結果或文件原始內容</li></ul><h3 id="_9-補弱點的-harness-會隨模型進步消失-校準-non-determinism-的-harness-永遠存在" tabindex="-1">#9：補弱點的 Harness 會隨模型進步消失；校準 Non-Determinism 的 Harness 永遠存在 <a class="header-anchor" href="#_9-補弱點的-harness-會隨模型進步消失-校準-non-determinism-的-harness-永遠存在" aria-label="Permalink to &quot;#9：補弱點的 Harness 會隨模型進步消失；校準 Non-Determinism 的 Harness 永遠存在&quot;">​</a></h3><ul><li>來源：RESEARCH.md + Rajasekaran + Trivedy</li><li><strong>行動意義</strong>: 投資 hooks + verification + planner-evaluator，這些不會被模型進步淘汰</li></ul><h3 id="_10-configuration-first-同模型-不同-harness-的性能差異-同-harness-不同模型" tabindex="-1">#10：Configuration-First；同模型 + 不同 Harness 的性能差異 &gt; 同 Harness + 不同模型 <a class="header-anchor" href="#_10-configuration-first-同模型-不同-harness-的性能差異-同-harness-不同模型" aria-label="Permalink to &quot;#10：Configuration-First；同模型 + 不同 Harness 的性能差異 &gt; 同 Harness + 不同模型&quot;">​</a></h3><ul><li>來源：Osmani + Terminal-Bench + HumanLayer + Masood</li><li><strong>行動意義</strong>: 下一個優化周期的投資應放在 CLAUDE.md 優化、hook 增強、skill 完善，而非等待新模型</li></ul><h3 id="_11-harness-可在運行時自適應-interface-調適成本-2-效果-95-2026-05" tabindex="-1">#11：Harness 可在運行時自適應；Interface 調適成本 2%，效果 95%（2026-05） <a class="header-anchor" href="#_11-harness-可在運行時自適應-interface-調適成本-2-效果-95-2026-05" aria-label="Permalink to &quot;#11：Harness 可在運行時自適應；Interface 調適成本 2%，效果 95%（2026-05）&quot;">​</a></h3><ul><li>來源：Adapting Interface, Not Model（2605.22166）</li><li><strong>行動意義</strong>: 優先投資運行時適應（工具綱目調整、prompt 動態組合）而非推理時適應</li></ul><h3 id="_12-harness-結構-五層分離-決定-40-性能差距-超過模型大小的影響-2026-05" tabindex="-1">#12：Harness 結構（五層分離）決定 40% 性能差距，超過模型大小的影響（2026-05） <a class="header-anchor" href="#_12-harness-結構-五層分離-決定-40-性能差距-超過模型大小的影響-2026-05" aria-label="Permalink to &quot;#12：Harness 結構（五層分離）決定 40% 性能差距，超過模型大小的影響（2026-05）&quot;">​</a></h3><ul><li>來源：Vesper（2605.15221）+ Runtime Substrate（2605.13357）</li><li><strong>行動意義</strong>: 架構設計（invocation/context/memory/coordination/reflection 層）是優化的主要槓桿</li></ul><h3 id="_13-harness-形式驗證可通過範疇論提供數學保證-2026-05" tabindex="-1">#13：Harness 形式驗證可通過範疇論提供數學保證（2026-05） <a class="header-anchor" href="#_13-harness-形式驗證可通過範疇論提供數學保證-2026-05" aria-label="Permalink to &quot;#13：Harness 形式驗證可通過範疇論提供數學保證（2026-05）&quot;">​</a></h3><ul><li>來源：Harness as Categorical Architecture（2605.12239）</li><li><strong>行動意義</strong>: 工具鏈的正確性不只依賴測試；可通過組合律形式化驗證</li></ul><h3 id="_14-基準評測完整性危機-67-排名系統存在污染信號-2026-05-重大發現" tabindex="-1">#14：基準評測完整性危機：67% 排名系統存在污染信號（2026-05 重大發現） <a class="header-anchor" href="#_14-基準評測完整性危機-67-排名系統存在污染信號-2026-05-重大發現" aria-label="Permalink to &quot;#14：基準評測完整性危機：67% 排名系統存在污染信號（2026-05 重大發現）&quot;">​</a></h3><ul><li>來源：Cheating Agents（DebugML 2026-05-23）</li><li><strong>行動意義</strong>: 現有 BENCHMARK.md 分數可能虛高；評測必須使用污染抵抗基準；需獨立驗證 Vesper/Terminal-Bench</li></ul><hr><h2 id="_6-2026-05-論文群綜合洞見" tabindex="-1">6. 2026-05 論文群綜合洞見 <a class="header-anchor" href="#_6-2026-05-論文群綜合洞見" aria-label="Permalink to &quot;6. 2026-05 論文群綜合洞見&quot;">​</a></h2><h3 id="主線-從靜態架構到動態自適應" tabindex="-1">主線：從靜態架構到動態自適應 <a class="header-anchor" href="#主線-從靜態架構到動態自適應" aria-label="Permalink to &quot;主線：從靜態架構到動態自適應&quot;">​</a></h3><p><strong>2026-05 共同主題</strong> = Harness 演化的三個新維度：</p><table tabindex="0"><thead><tr><th>維度</th><th>代表論文</th><th>核心發現</th></tr></thead><tbody><tr><td><strong>形式化</strong></td><td>Categorical Architecture (2605.12239)</td><td>Harness 可通過範疇論進行形式驗證，規則組合有數學保證</td></tr><tr><td><strong>動態性</strong></td><td>Continual Harness (2605.09998) + Meta-Harness (2603.28052)</td><td>Harness 無需模型重訓練即可在線學習演化；聯合優化收益 15-22%</td></tr><tr><td><strong>結構優越</strong></td><td>Vesper (2605.15221) + Substrate (2605.13357)</td><td>五層分離架構決定 40% 性能差距；超過模型大小影響</td></tr><tr><td><strong>運行時適應</strong></td><td>Interface Adaptation (2605.22166)</td><td>Harness 層適應成本 2% 但效果 95%；比模型層適應成本低 50 倍</td></tr><tr><td><strong>代碼即 Harness</strong></td><td>Code as Agent Harness (2605.18747)</td><td>型別、簽名、文件字串是隱含 harness；可從 AST 自動編譯工具綱目</td></tr></tbody></table><p><strong>綜合意義</strong>：</p><ul><li>Harness <strong>不是靜態配置</strong>，而是「可形式化、可自適應、有清晰分層的活系統」</li><li>投資方向：<strong>構建可參數化的五層架構</strong> + <strong>形式驗證工具</strong> + <strong>在線學習循環</strong></li><li>不要再等模型進步；harness 層的自適應速度已超過模型迭代周期</li></ul><hr><h3 id="風險警訊-基準污染危機" tabindex="-1">風險警訊：基準污染危機 <a class="header-anchor" href="#風險警訊-基準污染危機" aria-label="Permalink to &quot;風險警訊：基準污染危機&quot;">​</a></h3><p><strong>DebugML Cheating Agents（2026-05-23）</strong>：</p><ul><li>排名前 20 的 agent 系統中 <strong>67% 顯示污染信號</strong></li><li>涉及論文包括高影響力研究（Vesper、Terminal-Bench 等）</li><li>現有 BENCHMARK.md 的數字需視為「上界估計」而非事實</li></ul><p><strong>立即行動</strong>:</p><ol><li>對本 workspace 評測添加污染控制（out-of-distribution 保留集）</li><li>不再信任單一公開基準；採用「基準多樣化」策略</li><li>重要結論（如「harness 結構 40% 方差」）待獨立驗證前，視為「假設」</li></ol><hr><h2 id="_8-多代理協調模式-2026-05-整合" tabindex="-1">8. 多代理協調模式（2026-05 整合） <a class="header-anchor" href="#_8-多代理協調模式-2026-05-整合" aria-label="Permalink to &quot;8. 多代理協調模式（2026-05 整合）&quot;">​</a></h2><blockquote><p>來源：<code>multi-agent-coordination-2026.md</code>（2026-05-08，已歸檔至 archive/2026-05/）</p></blockquote><h3 id="核心命題" tabindex="-1">核心命題 <a class="header-anchor" href="#核心命題" aria-label="Permalink to &quot;核心命題&quot;">​</a></h3><p>生產環境多代理失敗率 <strong>41%-87%</strong>，主因是<strong>協調缺陷</strong>而非模型能力。「Bag of Agents」（無拓撲約束）可產生 <strong>17.2x 錯誤放大</strong>（DeepMind）。</p><h3 id="_45-規則-—-何時引入多代理" tabindex="-1">45% 規則 — 何時引入多代理 <a class="header-anchor" href="#_45-規則-—-何時引入多代理" aria-label="Permalink to &quot;45% 規則 — 何時引入多代理&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Single-Agent Baseline</th><th>多代理建議</th></tr></thead><tbody><tr><td>&lt; 45%</td><td>多代理最有效（最大收益）</td></tr><tr><td>45%-80%</td><td>謹慎評估，需明確並行化點</td></tr><tr><td>&gt; 80%</td><td><strong>不建議</strong>（噪音 &gt; 收益）</td></tr></tbody></table><p><strong>飽和閾值</strong>：≥ 4 個代理後，性能增益飽和或波動（Coordination Tax）。</p><h3 id="三種生產拓撲" tabindex="-1">三種生產拓撲 <a class="header-anchor" href="#三種生產拓撲" aria-label="Permalink to &quot;三種生產拓撲&quot;">​</a></h3><table tabindex="0"><thead><tr><th>拓撲</th><th>適用場景</th><th>錯誤放大</th><th>限制</th></tr></thead><tbody><tr><td>集中式（Hierarchical）</td><td>&gt; 8 agents，需全局狀態一致</td><td>~4.4x</td><td>Orchestrator 單點瓶頸</td></tr><tr><td>Mesh（去中心化）</td><td>3-8 個緊耦合代理</td><td>中</td><td>超出需拆分</td></tr><tr><td>Swarm（群體）</td><td>大規模並行、探索型任務</td><td>取決湧現</td><td>難以預測</td></tr></tbody></table><p><strong>混合模式</strong>（生產最常見）：Hierarchical orchestrator + Leaf teams 內部 Mesh + 單一 pipeline 階段啟動 Swarm。</p><h3 id="工業失敗模式-cogent-2026-playbook" tabindex="-1">工業失敗模式（Cogent 2026 Playbook） <a class="header-anchor" href="#工業失敗模式-cogent-2026-playbook" aria-label="Permalink to &quot;工業失敗模式（Cogent 2026 Playbook）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>失敗類型</th><th>緩解方案</th></tr></thead><tbody><tr><td>反饋循環（死鎖）</td><td>迴圈斷路器</td></tr><tr><td>虛假共識</td><td>獨立評估代理</td></tr><tr><td>API 預算耗盡</td><td>硬性 token 上限 + 監控</td></tr><tr><td>錯誤級聯</td><td>集中式拓撲 + 驗證節點</td></tr></tbody></table><h3 id="協議標準-2025-2026" tabindex="-1">協議標準（2025-2026） <a class="header-anchor" href="#協議標準-2025-2026" aria-label="Permalink to &quot;協議標準（2025-2026）&quot;">​</a></h3><ul><li><strong>MCP</strong>（Model Context Protocol）：代理存取外部工具和上下文的事實標準（Anthropic 主導）</li><li><strong>A2A</strong>（Agent-to-Agent Protocol）：代理間點對點協調、協商和委派</li><li>兩者組合 = 可互操作、可審計的分散式代理基礎設施</li></ul><hr><h2 id="_7-研究優先建議-action-items" tabindex="-1">7. 研究優先建議（Action Items） <a class="header-anchor" href="#_7-研究優先建議-action-items" aria-label="Permalink to &quot;7. 研究優先建議（Action Items）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>優先級</th><th>缺口</th><th>建議行動</th><th>預期收益</th><th>2026-05 聯動</th></tr></thead><tbody><tr><td><strong>P0</strong></td><td>基準污染防控</td><td>添加 out-of-distribution 保留集；獨立驗證 Vesper/Terminal-Bench</td><td>排除虛高數據，建立可信度</td><td>Cheating Agents 警訊</td></tr><tr><td><strong>P0</strong></td><td>五層架構實現</td><td>實現 Invocation/Context/Memory/Coordination/Reflection 層</td><td>清晰分層，可測試性 +40%</td><td>Runtime Substrate</td></tr><tr><td><strong>P0</strong></td><td>量化評估框架</td><td>完善 harness-eval skill</td><td>診斷本 workspace harness 水準</td><td>Vesper 方法論</td></tr><tr><td><strong>P0</strong></td><td>Rule Escalation 決策樹</td><td>新增 harness-design 規則</td><td>減少「prompt vs hook」的決策模糊</td><td>Meta-Harness 參數化</td></tr><tr><td><strong>P1</strong></td><td>Harness 形式驗證</td><td>實驗範疇論驗證工具鏈組合</td><td>規則正確性有數學保證</td><td>Categorical Architecture</td></tr><tr><td><strong>P1</strong></td><td>運行時自適應循環</td><td>實現在線 RL loop（工具選擇 + 順序調整）</td><td>Harness 無需重訓練即演化</td><td>Continual Harness + Meta-Harness</td></tr><tr><td><strong>P1</strong></td><td>Long-horizon 自動化</td><td>Progress 追蹤工具 + hook</td><td>跨 session 任務的穩健性</td><td>—</td></tr><tr><td><strong>P1</strong></td><td>Sub-agent 閾值驗證</td><td>A/B 測試不同委派閾值</td><td>優化委派的邊際效益點</td><td>—</td></tr><tr><td><strong>P2</strong></td><td>代碼即 Harness 實驗</td><td>從代碼 AST 自動編譯工具綱目</td><td>減少手工定義 schema 工作量</td><td>Code as Agent Harness</td></tr><tr><td><strong>P2</strong></td><td>Model upgrade checklist</td><td>升級指南文件</td><td>減少新模型版本的適應成本</td><td>Interface Adaptation 方法</td></tr><tr><td><strong>P3</strong></td><td>Cross-model portability</td><td>學術調查</td><td>長期研究價值</td><td>—</td></tr></tbody></table>',180)])])}const p=r(o,[["render",s]]);export{c as __pageData,p as default};
